#include <bits/stdc++.h>
using namespace std;
const int N=2e7+7,mod=1e9+7;
int n,a,b,c,g[N],prime[N],sum[N],mp[N],mi[N],cnt;
int ans=0;
bool is_prime[N];
void shai(){
    memset(is_prime,1,sizeof(is_prime));
    is_prime[0]=is_prime[1]=0,sum[1]=1;
    for(int i=2;i<=n;i++){
        if(is_prime[i])
            prime[++cnt]=i,sum[i]=2,mp[i]=i,mi[i]=1;
        for(int j=1;j<=cnt && i*prime[j]<=n;j++){
            is_prime[i*prime[j]]=0;
            mp[i*prime[j]]=prime[j];
            if(mp[i]==prime[j])
                sum[i*prime[j]]=sum[i]/(mi[i]+1)*(mi[i]+2),mi[i*prime[j]]=mi[i]+1;
            else
                sum[i*prime[j]]=sum[i]*2,mi[i*prime[j]]=1;
            if(i%prime[j]==0)
                break;
        }
    }
}
int main(){
    scanf("%d%d%d%d",&n,&a,&b,&c);
    scanf("%d",&g[n]);
    shai();
    for(int i=n-1;i;i--)
        g[i]=(1LL*a*g[i+1]%mod*g[i+1]%mod+1LL*b*g[i+1]%mod+c)%mod;
    int num=0;
    for(int i=1;i<=n;i++){
    	num+=sum[i-1],num%=mod;
        ans+=(1LL*num*(n-i+1)%mod*g[i]%mod+1LL*n*(n-i+1)%mod*g[i]%mod)%mod,ans%=mod;
    }
    printf("%d",ans);
    return 0;
}
